# Category: format_string

#include <stdio.h>
#include <time.h>
#include <string.h>

void log_error(const char *error_msg) {
    FILE *logfile = fopen("error_log.txt", "a");
    if (logfile == NULL) {
        return;
    }

    time_t now;
    time(&now);
    char time_str[20];
    strftime(time_str, sizeof(time_str), "%Y-%m-%d %H:%M:%S", localtime(&now));

    fprintf(logfile, "[%s] Error: %s\n", time_str, error_msg);
    fclose(logfile);
}